; Comprehensive property details include addresses, prices, virtual tour URLs, agent information (first name, last name, phone number, and email), and broker information (company name, address, phone number, and email); 
; View statistics include total views, average view duration in seconds, and the most commonly used device type for viewing; 
; Inquiries and offers refer to the total counts of inquiries and offers received for each property.

sql:
SELECT status, COUNT(*) AS offer_count
FROM property_offers
GROUP BY status;

SELECT COUNT(*) AS total_inquiries
FROM property_inquiries
WHERE property_id = 0;
